#!/usr/bin/env python3

from Crypto.Util.number import getStrongPrime, GCD

"""
Used to generate a pair of strong RSA keys
"""
def rsa_key_gen():
    e = 65537
    while 48763:
        p, q = getStrongPrime(2048), getStrongPrime(2048)
        n = p * q
        phi = (p - 1) * (q - 1)
        if GCD(e, phi)==1 and p!=q:
            break

    d = pow(e, -1, phi)
    return e, d, n

